changeSet.sql:
DECLARE @quizId1 BIGINT, @quizId2 BIGINT;

SELECT @quizId1 = id FROM quiz WHERE title = 'Relational Fundamentals';
SELECT @quizId2 = id FROM quiz WHERE title = 'SQL/Schema Design';

INSERT INTO question (quiz_id, prompt, question_type, points)
VALUES
    (@quizId1, 'Define the term "Atomicity" in the context of database transactions.', 'SHORT_ANSWER', 2.00),
    (@quizId1, 'True or False: A primary key can contain NULL values.', 'BOOLEAN', 1.00),
    (@quizId2, 'Write a SQL query to retrieve all students who scored above 90 on the midterm.', 'LONG_TEXT', 10.00),
    (@quizId2, 'Which normal form ensures there are no transitive dependencies?', 'MULTIPLE_CHOICE', 2.00);
